```

## Acceptance criteria

- [ ] Tool registered as `marketplace_search` in `registerMarketplaceTools()`.
- [ ] Input schema validated with Zod (defaults `limit` to 20, max 100).
- [ ] Returns structured JSON with `results` array and total count.
- [ ] Filters apply in order: type → category → tags → query.
- [ ] Honors `enabled: true` flag (skips disabled marketplaces unless explicit `marketplace` arg).
- [ ] When a marketplace fetch fails, logs a warning and continues with the others (does not throw).
- [ ] Tests cover: empty marketplace list, single marketplace, multiple marketplaces, type filter, query filter, tag filter, limit, fetch error fallback. Use a stub `MarketplaceSourceManager` and a stub `PackageFetcher` whose `fetchMarketplaceJson()` returns canned `MarketplaceJson` objects.

Create `apps/server/src/services/marketplace-mcp/tool-get.ts` exporting `createGetHandler(deps: MarketplaceMcpDeps)` that fetches full details for a single package by name, including the README content from its source.

## Files to create

- `apps/server/src/services/marketplace-mcp/tool-get.ts`
- `apps/server/src/services/marketplace-mcp/__tests__/tool-get.test.ts`

## Files to modify

- `apps/server/src/services/marketplace-mcp/marketplace-mcp-tools.ts` — add registration.

## Tool definition

```typescript
import { z } from 'zod';
import { readFile } from 'node:fs/promises';
import path from 'node:path';
import type { MarketplacePackageManifest } from '@dorkos/marketplace';
import type { MarketplaceMcpDeps } from './marketplace-mcp-tools.js';

export const GetInputSchema = {
  name: z.string().describe('Package name'),
  marketplace: z.string().optional().describe('Specific marketplace to look up the package in'),
};

export type GetInput = { name: string; marketplace?: string };
```

## Handler implementation

```typescript
export function createGetHandler(deps: MarketplaceMcpDeps) {
  return async (args: GetInput) => {
    // 1. Find the marketplace.json entry by searching all enabled sources
    //    (or the explicit one if provided).
    const sources = await deps.sourceManager.list();
    const candidates = args.marketplace
      ? sources.filter((s) => s.name === args.marketplace)
      : sources.filter((s) => s.enabled);

    let entry: { entry: import('@dorkos/marketplace').MarketplaceJsonEntry; marketplaceName: string } | null = null;
    for (const src of candidates) {
      try {
        const json = await deps.fetcher.fetchMarketplaceJson(src);
        const found = json.plugins.find((p) => p.name === args.name);
        if (found) {
          entry = { entry: found, marketplaceName: src.name };
          break;
        }
      } catch (err) {
        deps.logger.warn('[marketplace_get] failed to fetch marketplace.json', {
          marketplace: src.name,
          error: err instanceof Error ? err.message : String(err),
        });
      }
    }

    if (!entry) {
      return {
        content: [
          {
            type: 'text' as const,
            text: JSON.stringify(
              { error: `Package '${args.name}' not found`, code: 'PACKAGE_NOT_FOUND' },
              null,
              2
            ),
          },
        ],
        isError: true,
      };
    }

    // 2. Use the installer's preview() pipeline to fetch + validate the package
    //    so we get the full manifest (not just the marketplace.json entry).
    let manifest: MarketplacePackageManifest | null = null;
    let readme: string | undefined;
    try {
      const previewResult = await deps.installer.preview({
        name: args.name,
        marketplace: entry.marketplaceName,
      });
      manifest = previewResult.manifest;
      // README is best-effort: read from the staged package path if present.
      try {
        readme = await readFile(path.join(previewResult.packagePath, 'README.md'), 'utf-8');
      } catch {
        readme = undefined;
      }
    } catch (err) {
      deps.logger.warn('[marketplace_get] preview() failed; returning marketplace.json entry only', {
        package: args.name,
        error: err instanceof Error ? err.message : String(err),
      });
    }

    return {
