```typescript
import type { MarketplaceJsonEntry } from '@dorkos/marketplace';

/** Single scored recommendation result. */
export interface ScoredRecommendation {
  entry: MarketplaceJsonEntry;
  marketplace: string;
  score: number;
  reason: string;
}

/**
 * Score marketplace entries against a free-text context. Higher score = more
 * relevant. Returns at most `limit` entries sorted by score descending; entries
 * with score 0 are filtered out.
 *
 * Scoring weights:
 * - Name token match: +10 per token
 * - Description token match: +3 per token
 * - Exact tag match: +5 per match
 * - Featured boost: +2
 */
export function recommend(
  entries: { entry: MarketplaceJsonEntry; marketplace: string }[],
  context: string,
  limit: number
): ScoredRecommendation[];

/**
 * Tokenize a context string into lowercase keywords. Strips punctuation,
 * filters out stopwords (a, the, an, in, my, of, for, and, to), drops tokens
 * shorter than 3 characters.
 */
export function tokenize(context: string): string[];
```

## Implementation

```typescript
const STOPWORDS = new Set([
  'a', 'an', 'the', 'in', 'on', 'of', 'for', 'and', 'to', 'my', 'is', 'it',
  'with', 'that', 'this', 'i', 'me', 'we', 'us', 'or', 'be', 'as', 'at',
]);

export function tokenize(context: string): string[] {
  return context
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, ' ')
    .split(/\s+/)
    .filter((token) => token.length >= 3 && !STOPWORDS.has(token));
}

export function recommend(
  entries: { entry: MarketplaceJsonEntry; marketplace: string }[],
  context: string,
  limit: number
): ScoredRecommendation[] {
  const tokens = tokenize(context);
  if (tokens.length === 0) return [];

  const scored: ScoredRecommendation[] = entries.map(({ entry, marketplace }) => {
    let score = 0;
    const reasons: string[] = [];

    const name = entry.name.toLowerCase();
    for (const token of tokens) {
      if (name.includes(token)) {
        score += 10;
        reasons.push(`name matches "${token}"`);
      }
    }

    const desc = (entry.description ?? '').toLowerCase();
    for (const token of tokens) {
      if (desc.includes(token)) {
        score += 3;
        reasons.push(`description matches "${token}"`);
      }
    }

    for (const tag of entry.tags ?? []) {
      const tagLc = tag.toLowerCase();
      for (const token of tokens) {
        if (tagLc === token) {
          score += 5;
          reasons.push(`tag "${tag}"`);
        }
      }
    }

    if (entry.featured) score += 2;

    return {
      entry,
      marketplace,
      score,
      reason: reasons.slice(0, 3).join(', '),
    };
  });

  return scored
    .filter((s) => s.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);
}
```

