```typescript
export function createInstallHandler(deps: MarketplaceMcpDeps) {
  return async (args: {
    name: string;
    marketplace?: string;
    type?: 'agent' | 'plugin' | 'skill-pack' | 'adapter';
    projectPath?: string;
    confirmationToken?: string;
  }) => {
    // 1. Build permission preview FIRST. This catches missing packages,
    //    validation failures, and conflicts before any disk mutation.
    let preview;
    try {
      preview = await deps.installer.preview({
        name: args.name,
        marketplace: args.marketplace,
        projectPath: args.projectPath,
      });
    } catch (err) {
      return errorContent(err, 'PREVIEW_FAILED');
    }

    // 2. Resolve confirmation. If the caller passed a token, look it up.
    //    Otherwise request a new confirmation.
    let confirmation;
    if (args.confirmationToken) {
      confirmation = await deps.confirmationProvider.resolveToken(args.confirmationToken);
    } else {
      confirmation = await deps.confirmationProvider.requestInstallConfirmation({
        packageName: args.name,
        marketplace: args.marketplace ?? 'dorkos-community',
        operation: 'install',
        preview: preview.preview,
      });
    }

    if (confirmation.status === 'pending') {
      return jsonContent({
        status: 'requires_confirmation',
        preview: preview.preview,
        confirmationToken: confirmation.token,
        message:
          'User must confirm install before proceeding. Re-call this tool with the confirmationToken once the user has approved.',
      });
    }
    if (confirmation.status === 'declined') {
      return jsonContent({
        status: 'declined',
        reason: confirmation.reason ?? 'User declined installation',
      });
    }

    // 3. Approved — proceed with install.
    try {
      const result = await deps.installer.install({
        name: args.name,
        marketplace: args.marketplace,
        projectPath: args.projectPath,
      });
      return jsonContent({
        status: 'installed',
        package: {
          name: result.packageName,
          version: result.version,
          type: result.type,
        },
        installPath: result.installPath,
        warnings: result.warnings,
      });
    } catch (err) {
      if (err instanceof ConflictError) {
        return errorContent(err, 'CONFLICT', { conflicts: err.conflicts });
      }
      if (err instanceof InvalidPackageError) {
        return errorContent(err, 'INVALID_PACKAGE', { errors: err.errors });
      }
      return errorContent(err, 'INSTALL_FAILED');
    }
  };
}

function jsonContent(data: unknown) {
  return { content: [{ type: 'text' as const, text: JSON.stringify(data, null, 2) }] };
}

function errorContent(err: unknown, code: string, extra?: Record<string, unknown>) {
  const message = err instanceof Error ? err.message : String(err);
  return {
    content: [
      {
        type: 'text' as const,
        text: JSON.stringify({ error: message, code, ...extra }, null, 2),
      },
    ],
    isError: true,
  };
}
```

