export function createUninstallHandler(deps: MarketplaceMcpDeps) {
  return async (args: {
    name: string;
    purge?: boolean;
    projectPath?: string;
    confirmationToken?: string;
  }) => {
    // 1. Resolve confirmation.
    let confirmation;
    if (args.confirmationToken) {
      confirmation = await deps.confirmationProvider.resolveToken(args.confirmationToken);
    } else {
      confirmation = await deps.confirmationProvider.requestInstallConfirmation({
        packageName: args.name,
        marketplace: 'installed',
        operation: 'uninstall',
      });
    }

    if (confirmation.status === 'pending') {
      return jsonContent({
        status: 'requires_confirmation',
        confirmationToken: confirmation.token,
        message:
          'User must confirm uninstall before proceeding. Re-call this tool with the confirmationToken once the user has approved.',
      });
    }
    if (confirmation.status === 'declined') {
      return jsonContent({
        status: 'declined',
        reason: confirmation.reason ?? 'User declined uninstall',
      });
    }

    // 2. Approved — proceed with uninstall.
    try {
      const result = await deps.uninstallFlow.uninstall({
        name: args.name,
        purge: args.purge ?? false,
        projectPath: args.projectPath,
      });
      return jsonContent({
        status: 'uninstalled',
        package: { name: result.packageName, type: result.type },
        purgedPaths: result.purgedPaths ?? [],
        preservedPaths: result.preservedData ?? [],
      });
    } catch (err) {
      if (err instanceof PackageNotInstalledError) {
        return errorContent(err, 'NOT_INSTALLED');
      }
      return errorContent(err, 'UNINSTALL_FAILED');
    }
  };
}
